import axios from "axios";
import Cookies from "js-cookie";
import { encrypt, decrypt } from "../../helper/cryptojs";
import proxy from "../../helper/proxy";

const API_URL = `${proxy()}/user`;

//register
const register = async (userData) => {
  const data = await encrypt(userData);
  const response = await axios.post(API_URL, { data });
  const res = {};
  if (response.data) {
    res.user = await decrypt(response.data.data);
    res.message = response.data.message;
    localStorage.setItem("token", await encrypt(res.user.token));
    Cookies.set("user", JSON.stringify(res.user));
  }
  return res;
};

//login
const login = async (userData) => {
  const data = await encrypt(userData);
  const response = await axios.post(`${API_URL}/login`, { data });
  const res = {};
  if (response.data) {
    res.user = await decrypt(response.data.data);
    res.message = response.data.message;
    localStorage.setItem("token", await encrypt(res.user.token));
    Cookies.set("user", JSON.stringify(res.user));
    console.log(res);
  }
  return res;
};

const userService = {
  register,
  login,
};

export default userService;
