import { ErrorMessage, useField } from "formik";
import { useMediaQuery } from "react-responsive";
import style from "./FormComponents.module.css";
export const TextInput = ({
  placeholder,
  bottom,
  right,
  screenXl,
  ...props
}) => {
  const [field, meta] = useField(props);
  const dexktopView = useMediaQuery({
    query: "(min-width:850px)",
  });
  const dexktopViewXl = useMediaQuery({
    query: "(min-width:1020px)",
  });
  return (
    <div
      className={style.component_wrap}
      style={{
        width: `${
          screenXl
            ? dexktopViewXl
              ? "370px"
              : "320px"
            : dexktopView
            ? "360px"
            : "320px"
        }`,
      }}
    >
      {meta.touched &&
        meta.error &&
        !bottom &&
        (!right ? (
          <div
            className={`${style.error} ${
              screenXl ? style.error_xl : style.error_md
            }`}
          >
            <ErrorMessage name={field.name} />
            <div
              className={
                screenXl
                  ? dexktopViewXl
                    ? `${style.error_arrow} ${style.arrow_left}`
                    : `${style.error_arrow} ${style.arrow_top}`
                  : dexktopView
                  ? `${style.error_arrow} ${style.arrow_left}`
                  : `${style.error_arrow} ${style.arrow_top}`
              }
            ></div>
          </div>
        ) : (
          <div
            className={`${style.error} ${
              screenXl ? style.error_xl : style.error_md
            }`}
          >
            <ErrorMessage name={field.name} />
            <div
              className={
                screenXl
                  ? dexktopViewXl
                    ? `${style.error_arrow} ${style.arrow_right}`
                    : `${style.error_arrow} ${style.arrow_top}`
                  : dexktopView
                  ? `${style.error_arrow} ${style.arrow_right}`
                  : `${style.error_arrow} ${style.arrow_top}`
              }
            ></div>
          </div>
        ))}

      <input
        type={field.type}
        name={field.name}
        placeholder={placeholder}
        {...field}
        {...props}
        className={
          meta.touched && meta.error ? "border-[#b94a48]" : "border-bgThird"
        }
      />
      {meta.touched &&
        meta.error &&
        bottom &&
        (!right ? (
          <div
            className={`${style.error_bottom} ${
              screenXl ? style.error_bottom_xl : style.error_bottom_md
            }`}
          >
            <ErrorMessage name={field.name} />
            <div
              className={
                screenXl
                  ? dexktopViewXl
                    ? `${style.error_arrow} ${style.arrow_left}`
                    : `${style.error_arrow} ${style.arrow_bottom}`
                  : dexktopView
                  ? `${style.error_arrow} ${style.arrow_left}`
                  : `${style.error_arrow} ${style.arrow_bottom}`
              }
            ></div>
          </div>
        ) : (
          <div
            className={`${style.error_bottom} ${
              screenXl
                ? style.error_bottom_xl_right
                : style.error_bottom_md_right
            }`}
          >
            <ErrorMessage name={field.name} />
            <div
              className={
                screenXl
                  ? dexktopViewXl
                    ? `${style.error_arrow} ${style.arrow_right}`
                    : `${style.error_arrow} ${style.arrow_bottom}`
                  : dexktopView
                  ? `${style.error_arrow} ${style.arrow_right}`
                  : `${style.error_arrow} ${style.arrow_bottom}`
              }
            ></div>
          </div>
        ))}
      {meta.touched && meta.error && (
        <i
          className={style.error_icon}
          style={{
            top: `${
              screenXl
                ? !bottom && !dexktopViewXl
                  ? "60%"
                  : "15px"
                : !bottom && !dexktopView
                ? "60%"
                : "15px"
            }`,
          }}
        ></i>
      )}
    </div>
  );
};
