import { Formik, Form } from "formik";
import * as Yup from "yup";
import { useState, useEffect } from "react";
import { Link } from "react-router-dom";
import { TextInput } from "../../components/inputs/FormComponents";
import SyncLoader from "react-spinners/SyncLoader";
import { useSelector, useDispatch } from "react-redux";
import { toast } from "react-toastify";
import { useNavigate } from "react-router-dom";
import { login, reset } from "../../features/user/userSlice";
import style from "./User.module.css";

export default function LoginForm({ setVisible, visible }) {
  const dispatch = useDispatch();
  const navigate = useNavigate();
  const [error, setError] = useState("");
  const [success, setSuccess] = useState("");
  const [loading, setLoading] = useState(false);
  const [submit, setSubmit] = useState(false);

  const loginInfos = {
    email: "",
    password: "",
  };

  const { email, password } = loginInfos;
  const { status, message } = useSelector((state) => state.user);

  const loginValidation = Yup.object({
    email: Yup.string()
      .required("Email adresi zorunlu")
      .email("Email geçerli değil"),
    password: Yup.string()
      .required("Şifre zorunlu")
      .min(6, "Şifre enaz 6 karakter olmalı")
      .max(40, "Sifre enfazla 40 karakter olmalı"),
  });

  const handeleSubmit = (data, actions) => {
    dispatch(login(data));
  };

  useEffect(() => {
    if (!visible) {
      if (status === "loading") {
        setLoading(true);
        setSubmit(true);
        setError("");
        setSuccess("");
      }

      if (status === "error") {
        setLoading(false);
        setSubmit(false);
        setError(message);
        setSuccess("");
        toast.error(message);
        dispatch(reset());
      }

      if (status === "success") {
        setLoading(false);
        setSubmit(false);
        setError("");
        setSuccess(message);
        toast.success(message);
        dispatch(reset());
        setTimeout(() => {
          navigate("/");
        }, 2000);
      }
    }
  }, [status, message, dispatch, navigate]);

  return (
    <div className={style.loginWrap}>
      <div className={style.login1}>
        <img src="../../icons/logo_tam.svg" alt="" />
        <span>
          Paylaşılan resim ve videoları beğenmek ve yorum yapmak için giriş
          yapın.
        </span>
      </div>
      <div className={style.login2}>
        <div className={style.login2Wrap}>
          <Formik
            enableReinitialize
            initialValues={{
              email,
              password,
            }}
            validationSchema={loginValidation}
            onSubmit={handeleSubmit}
          >
            {(formik) => (
              <Form>
                <TextInput
                  type="email"
                  placeholder="E-posta adresi"
                  name="email"
                  disabled={submit}
                />
                <TextInput
                  type="password"
                  placeholder="Şifre"
                  name="password"
                  bottom
                  disabled={submit}
                />
                <button
                  type="submit"
                  className={style.blueBtn}
                  disabled={submit}
                >
                  Giriş Yap
                </button>
              </Form>
            )}
          </Formik>
          <Link to="/forget">Şifremi unuttum</Link>
          <SyncLoader color="#1876f2" loading={loading} size={10} />
          {error && <div className={style.errorText}>{error}</div>}
          {success && <div className={style.succesText}>{success}</div>}
          <div className={style.signSplitter}></div>
          <button
            className={`${style.blueBtn} ${style.openSignup}`}
            onClick={() => setVisible(true)}
          >
            Kayıt Ol
          </button>
        </div>
        <Link to="/">
          <b>Ana Sayfaya dön</b>
        </Link>
      </div>
    </div>
  );
}
