import { Link, NavLink } from "react-router-dom";
import Logo from "../../../svg/Logo";
import style from "./Header.module.css";

export default function Header() {
  return (
    <header className={style.header}>
      <div className={style.header_left}>
        <Link to="/" className="header_logo">
          <div className={style.circle}>
            <Logo height="50" color="#000" />
          </div>
        </Link>
      </div>
      <div className={style.header_middle}>
        <NavLink
          to="/"
          className={({ isActive }) =>
            isActive
              ? `${style.middle_icon} ${style.active}`
              : style.middle_icon
          }
        >
          <span>Ana Sayfa</span>
        </NavLink>
        <NavLink
          to="/galeri"
          className={({ isActive }) =>
            isActive
              ? `${style.middle_icon} ${style.active}`
              : style.middle_icon
          }
        >
          <span>Galeri</span>
        </NavLink>
        <NavLink
          to="/randevu"
          className={({ isActive }) =>
            isActive
              ? `${style.middle_icon} ${style.active}`
              : style.middle_icon
          }
        >
          <span>Randevu</span>
        </NavLink>
        <NavLink
          to="/iletisim"
          className={({ isActive }) =>
            isActive
              ? `${style.middle_icon} ${style.active}`
              : style.middle_icon
          }
        >
          <span>İletişim</span>
        </NavLink>
      </div>
      <div className="header_right"></div>
    </header>
  );
}
