import { Form, Formik } from "formik";
import { useEffect, useState } from "react";
import * as Yup from "yup";
import { TextInput } from "../inputs/FormComponents";
import SyncLoader from "react-spinners/SyncLoader";
import { useSelector, useDispatch } from "react-redux";
import { toast } from "react-toastify";
import { register, reset } from "../../features/user/userSlice";
import { useNavigate } from "react-router-dom";
import style from "./User.module.css";

export default function RegisterForm({ setVisible }) {
  const userInfo = {
    ad: "",
    soyad: "",
    email: "",
    password: "",
  };

  const { ad, soyad, email, password } = userInfo;
  const { user, status, message } = useSelector((state) => state.user);
  const dispatch = useDispatch();
  const navigation = useNavigate();

  const [error, setError] = useState("");
  const [success, setSuccess] = useState("");
  const [loading, setLoading] = useState(false);
  const [submit, setSubmit] = useState(false);

  const registerValidation = Yup.object({
    ad: Yup.string()
      .required("Adın nedir?")
      .min(3, "Adınız enaz 3 karakter olmalı")
      .max(30, "Adınız enfazla 30 karakter olmalı")
      .matches(
        /^([aA-zZğĞüÜşŞİıöÖçÇ]+)(\s([aA-zZğĞüÜşŞİıöÖçÇ]+))?$/,
        "Adınız özel karakter, rakam ve sonunda boşluk içeremez"
      ),
    soyad: Yup.string()
      .required("Soyadın nedir?")
      .min(2, "Soyadın enaz 2 karakter olmalı")
      .max(30, "Soyadın enfazla 30 karakter olmalı")
      .matches(
        /^[aA-zZğĞüÜşŞİıöÖçÇ]+$/,
        "Soyadınız özel karakter, rakam ve sonunda boşluk içeremez"
      ),
    email: Yup.string()
      .required("E-pasta adresin nedir?")
      .email("E-posta adresiniz geçerli değil"),
    password: Yup.string()
      .required("Şifren nedir?")
      .min(6, "Şifreniz enaz 6 karakter olmalı")
      .max(40, "Şifreniz enfazla 40 karakter olmalı"),
  });

  const handleSubmit = (data, action) => {
    dispatch(register(data));
    //action.setSubmitting(false);
  };

  useEffect(() => {
    if (status === "loading") {
      setLoading(true);
      setSubmit(true);
      setError("");
      setSuccess("");
    }
    if (status === "error") {
      setLoading(false);
      setSubmit(false);
      setError(message);
      toast.error(message);
      dispatch(reset());
    }
    if (status === "success") {
      setLoading(false);
      setSubmit(false);
      setSuccess(message);
      toast.success(message);
      dispatch(reset());
      setTimeout(() => {
        navigation("/");
      }, 2000);
    }
  }, [status]);
  return (
    <div className={style.modeBlur}>
      <div className={style.register}>
        <div className={style.registerHeader}>
          <i
            className={`${style.exitIcon} ${style.registerExitIcon}`}
            onClick={() => setVisible(false)}
          ></i>
          <span>Kaydol</span>
          <span>Hızlı ve kolaydır.</span>
        </div>
        <Formik
          enableReinitialize
          initialValues={{
            ad,
            soyad,
            email,
            password,
          }}
          validationSchema={registerValidation}
          onSubmit={handleSubmit}
        >
          {(formik) => (
            <Form className={style.registerForm}>
              <div className={`${style.regLine} md:!w-full xl:!flex-row`}>
                <TextInput
                  screenXl
                  bottom
                  name="ad"
                  placeholder="Adınız"
                  type="text"
                  disabled={submit}
                />
                <TextInput
                  screenXl
                  bottom
                  right
                  name="soyad"
                  placeholder="Soyadınız"
                  type="text"
                  disabled={submit}
                />
              </div>

              <div className={style.regLine}>
                <TextInput
                  screenXl
                  bottom
                  name="email"
                  placeholder="E-posta Adresiniz"
                  type="email"
                  disabled={submit}
                />
              </div>
              <div className={style.regLine}>
                <TextInput
                  screenXl
                  bottom
                  name="password"
                  placeholder="Şifreniz"
                  type="password"
                  disabled={submit}
                />
              </div>
              <div className={style.regInfo}>
                Kaydol düğmesine tıklayarak, <span>Koşullarımızı</span>,&nbsp;
                <span>Gizlilik İlkemizi</span>&nbsp; ve&nbsp;
                <span>Çerezler İlkemizi</span> kabul etmiş olursun. Bizden SMS
                Bildirimleri alabilir ve bu bildirimleri istediğin zaman
                durdurabilirsin.
              </div>
              <div className={style.regBtnWrapper}>
                <button
                  disabled={submit}
                  type="submit"
                  className={`${style.blueBtn} ${style.openSignup}`}
                >
                  Kaydol
                </button>
              </div>
              <SyncLoader color="#1876f2" loading={loading} size={10} />
              {error && <div className={style.errorText}>{error}</div>}
              {success && <div className={style.succesText}>{success}</div>}
            </Form>
          )}
        </Formik>
      </div>
    </div>
  );
}
